// Entrada da IA/subworkflow
const params = $input.first().json || {};
const esc = (s) => String(s).replace(/'/g, "''");
const conditions = [];

// tipo
if (params.tipo && String(params.tipo).trim()) {
  conditions.push(`tipo = '${esc(params.tipo)}'`);
}

// categoria
if (params.categoria && String(params.categoria).trim()) {
  conditions.push(`categoria ILIKE '%${esc(params.categoria)}%'`);
}

// origem
if (params.origem && String(params.origem).trim()) {
  conditions.push(`origem ILIKE '%${esc(params.origem)}%'`);
}

// descricao (busca parcial)
if (params.descricao && String(params.descricao).trim()) {
  conditions.push(`descricao ILIKE '%${esc(params.descricao)}%'`);
}

// valor (igual exato, só se número)
if (params.valor !== undefined && params.valor !== null && !Number.isNaN(Number(params.valor))) {
  conditions.push(`valor = ${Number(params.valor)}`);
}

// data pode ser: 'YYYY-MM-DD', 'YYYY-MM', ou 'YYYY-MM-DD to YYYY-MM-DD'
if (params.data && String(params.data).trim()) {
  const d = String(params.data).trim();
  const rangeMatch = d.match(/^(\d{4}-\d{2}-\d{2})\s+to\s+(\d{4}-\d{2}-\d{2})$/);
  const dayMatch = d.match(/^\d{4}-\d{2}-\d{2}$/);
  const monthMatch = d.match(/^\d{4}-\d{2}$/);

  if (rangeMatch) {
    // Período: usar operadores de comparação de data
    const from = esc(rangeMatch[1]);
    const to = esc(rangeMatch[2]);
    conditions.push(`data >= '${from}'::date AND data <= '${to}'::date`);
  } else if (dayMatch) {
    // Dia específico: comparação direta
    conditions.push(`data = '${esc(d)}'::date`);
  } else if (monthMatch) {
    // Mês: converter data para texto ou usar DATE_TRUNC
    // Opção 1: Conversão para texto (mais simples)
    conditions.push(`data::text LIKE '${esc(d)}%'`);

    // Opção 2: Usar intervalo de datas (mais eficiente, comentado abaixo)
    // const year = d.substring(0, 4);
    // const month = d.substring(5, 7);
    // const nextMonth = String(parseInt(month) + 1).padStart(2, '0');
    // const nextYear = nextMonth === '13' ? String(parseInt(year) + 1) : year;
    // const nextMonthStr = nextMonth === '13' ? '01' : nextMonth;
    // conditions.push(`data >= '${year}-${month}-01'::date AND data < '${nextYear}-${nextMonthStr}-01'::date`);
  } else {
    // formato desconhecido: não aplicar filtro de data
  }
}

const whereClause = conditions.length ? `WHERE ${conditions.join(' AND ')}` : '';

const query = `
  SELECT id, valor, descricao, categoria, tipo, origem, data, created_at
  FROM financeiro.transacoes
  ${whereClause}
  ORDER BY data DESC, created_at DESC
  LIMIT 50
`;

return [{ json: { query, filtros_aplicados: conditions, total_filtros: conditions.length } }];

// Pega os resultados da query
const transacoes = $input.all().map(i => i.json);

// Se não tiver nada
if (!transacoes || transacoes.length === 0) {
  return [{
    json: {
      frases: ["Nenhuma transação encontrada."],
      total: 0
    }
  }];
}

// Monta as frases
const frases = transacoes.map(t => {
  return `${t.tipo === "entrada" ? "Entrada" : "Saída"} de R$ ${Number(t.valor).toFixed(2)} em ${t.data.split("T")[0]} (${t.descricao})`;
});

// Soma total (valores numéricos)
const total = transacoes.reduce((acc, t) => acc + Number(t.valor), 0);

// Retorna já pronto
return [{
  json: {
    frases,
    total: Number(total.toFixed(2))
  }
}];
